/// ML-KEM 768 Interoperability Test: Dart pqcrypto vs Rust ml-kem
///
/// This script takes hex-encoded values from the Rust ml-kem crate
/// (private key + ciphertext) and attempts decapsulation using the
/// Dart pqcrypto package. If the shared secrets match, the libraries
/// are interoperable. If not, they are mathematically incompatible.
import 'dart:typed_data';
import 'package:pqcrypto/pqcrypto.dart';

// ====================================================================
// VALUES FROM RUST ml-kem 0.2.3 (generated by rust_baseline)
// ====================================================================
const dkHex =
    '';

const ctHex =
    '';

const expectedSsHex =
    'c7fa37106d73995e322045b563c1d9729af01a5e8a04d070fcff87629e7a5957';

/// Convert hex string to byte array.
Uint8List hexToBytes(String hex) {
  final result = Uint8List(hex.length ~/ 2);
  for (var i = 0; i < hex.length; i += 2) {
    result[i ~/ 2] = int.parse(hex.substring(i, i + 2), radix: 16);
  }
  return result;
}

/// Convert byte array to hex string.
String bytesToHex(Uint8List bytes) {
  return bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join();
}

void main() {
  print('=== ML-KEM 768 Interoperability Test ===');
  print('Dart pqcrypto 0.1.0 vs Rust ml-kem 0.2.3');
  print('');

  // Step 3: Convert hex strings to byte arrays
  final dkBytes = hexToBytes(dkHex);
  final ctBytes = hexToBytes(ctHex);
  final expectedSs = hexToBytes(expectedSsHex);

  print('DK length: ${dkBytes.length} bytes (expected 2400)');
  print('CT length: ${ctBytes.length} bytes (expected 1088)');
  print('Expected SS length: ${expectedSs.length} bytes (expected 32)');
  print('');

  // Step 4: Execute decapsulation
  final kem = PqcKem.kyber768;

  try {
    final dartSs = kem.decapsulate(dkBytes, ctBytes);
    final dartSsHex = bytesToHex(dartSs);

    print('Rust shared secret:  $expectedSsHex');
    print('Dart shared secret:  $dartSsHex');
    print('');

    // Step 5: Compare and diagnose
    if (dartSsHex == expectedSsHex) {
      print('RESULT: MATCH - Libraries are fully interoperable!');
      print('');
      print('Diagnosis: The ML-KEM implementation is mathematically');
      print('identical. Any handshake bugs are in the WebSocket,');
      print('Base64 encoding, or JSON parsing layers.');
    } else {
      print('RESULT: MISMATCH - Libraries are NOT interoperable!');
      print('');
      print('Diagnosis: The Dart pqcrypto package produces different');
      print('shared secrets than Rust ml-kem. The Dart package may');
      print('be using an outdated NIST draft. You must use FFI bindings');
      print('to the same Rust crate (which KTTY already does via');
      print('flutter_rust_bridge).');
      print('');
      print('Note: KTTY already uses Rust FFI for ML-KEM on both sides,');
      print('so this mismatch only affects standalone Dart pqcrypto usage.');
    }
  } catch (e, st) {
    print('ERROR: Decapsulation failed!');
    print('Exception: $e');
    print('Stack: ${st.toString().split('\n').take(5).join('\n')}');
    print('');
    print('Diagnosis: Key format incompatibility between Rust ml-kem');
    print('and Dart pqcrypto. The serialization formats differ.');
  }

  // Bonus: Self-test with Dart-only operations
  print('');
  print('=== Dart Self-Test ===');
  final (dartPk, dartSk) = PqcKem.kyber768.generateKeyPair();
  print('Generated Dart keypair: pk=${dartPk.length} bytes, sk=${dartSk.length} bytes');

  final (dartCt, dartEncSs) = kem.encapsulate(dartPk);
  print('Encapsulated: ct=${dartCt.length} bytes, ss=${dartEncSs.length} bytes');

  final dartDecSs = kem.decapsulate(dartSk, dartCt);
  print('Decapsulated: ss=${dartDecSs.length} bytes');

  final selfTestMatch = bytesToHex(dartEncSs) == bytesToHex(dartDecSs);
  print('Dart self-test: ${selfTestMatch ? "PASSED" : "FAILED"}');
}
